CREATE OR REPLACE FUNCTION what_quarter_is(date_in DATE, start_month INTEGER)
RETURNS INTEGER AS $$
DECLARE
    month_offset INTEGER;
    adjusted_month INTEGER;
BEGIN
    -- Calculate the offset from the start month
    month_offset := (EXTRACT(MONTH FROM date_in) - start_month + 12) % 12;

    -- Adjust month to be 0-11 relative to start_month
    adjusted_month := month_offset;

    -- Calculate which quarter (0-3) and add 1 to make it 1-4
    RETURN FLOOR(adjusted_month / 3) + 1;
END;
$$ LANGUAGE plpgsql;

-- Example usage:
-- SELECT what_quarter_is('1995-07-23', 4); -- Returns 2
-- SELECT what_quarter_is('1995-04-15', 4); -- Returns 1 (April, May, June = Q1)
-- SELECT what_quarter_is('1995-01-15', 4); -- Returns 4 (January, February, March = Q4)

