CREATE OR REPLACE FUNCTION reindex_superhero_hair_colours(IN publisher_id_param BIGINT) 
RETURNS VOID 
LANGUAGE plpgsql 
AS $$
DECLARE
    temp_seq TEXT := 'temp_hair_colour_seq_' || pg_backend_pid();
    hero_record RECORD;
    new_id INTEGER;
BEGIN
    -- Create a temporary sequence
    EXECUTE 'CREATE TEMPORARY SEQUENCE ' || temp_seq || ' START WITH 1 INCREMENT BY 1';

    -- Reset the sequence
    EXECUTE 'ALTER SEQUENCE ' || temp_seq || ' RESTART';

    -- Loop through each superhero of the given publisher ordered by their current hair_colour_id
    FOR hero_record IN 
        SELECT id, hair_colour_id 
        FROM superhero 
        WHERE publisher_id = publisher_id_param 
        ORDER BY hair_colour_id, id
    LOOP
        -- Get next value from sequence
        EXECUTE 'SELECT nextval(''' || temp_seq || ''')' INTO new_id;

        -- Update the hair_colour_id
        UPDATE superhero 
        SET hair_colour_id = new_id 
        WHERE id = hero_record.id;
    END LOOP;

    -- Drop the temporary sequence
    EXECUTE 'DROP SEQUENCE ' || temp_seq;
END;
$$

CREATE TABLE log_content (
    "log_id" INT GENERATED BY DEFAULT AS IDENTITY NOT NULL, 
    "content" VARCHAR(32) NOT NULL, 
    "no_of_chars" INT NULL, 
    PRIMARY KEY ("log_id")
);

CREATE OR REPLACE FUNCTION update_char_count()
RETURNS TRIGGER AS $$
BEGIN
    NEW.no_of_chars := CHAR_LENGTH(NEW.content);
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

CREATE TRIGGER log_content_char_count_trigger
    BEFORE INSERT ON log_content
    FOR EACH ROW
    EXECUTE FUNCTION update_char_count()

