CREATE OR REPLACE PROCEDURE insertMore()
LANGUAGE plpgsql
AS $$
DECLARE
    v_start INT;
    v_counter INT := 1;
    v_end INT;
BEGIN
    -- Get the current row count
    SELECT COUNT(*) INTO v_end FROM table1;

    -- Get the next available ID (handle empty table case)
    SELECT COALESCE(MAX(id), 0) + 1 INTO v_start FROM table1;

    -- Insert rows equal to the original count
    WHILE (v_counter <= v_end) LOOP
        INSERT INTO table1 VALUES (v_start, DEFAULT, v_counter, v_start + v_counter, v_end);
        v_counter := v_counter + 1;
        v_start := v_start + 1;  -- Increment start for next row
    END LOOP;
END;
$$

CREATE OR REPLACE FUNCTION FIND_TEST_TABLE_COLUMN(
    IN_COLUMN1 VARCHAR,
    IN_COLUMN2 VARCHAR,
    IN_COLUMN3 VARCHAR,
    IN_COLUMN4 VARCHAR,
    IN_REQUESTED_COLUMN VARCHAR
) RETURNS VARCHAR AS $$
DECLARE
    RESULT VARCHAR;
    query TEXT;
BEGIN
    -- Validate the requested column parameter
    IF IN_REQUESTED_COLUMN NOT IN ('COLUMN1', 'COLUMN2', 'COLUMN3', 'COLUMN4') THEN
        RAISE EXCEPTION 'Invalid column name: %', IN_REQUESTED_COLUMN;
    END IF;

    -- Build the query dynamically
    query := 'SELECT ';

    -- Add the requested column to SELECT clause
    CASE IN_REQUESTED_COLUMN
        WHEN 'COLUMN1' THEN query := query || 'column1';
        WHEN 'COLUMN2' THEN query := query || 'column2';
        WHEN 'COLUMN3' THEN query := query || 'column3';
        WHEN 'COLUMN4' THEN query := query || 'column4';
    END CASE;

    query := query || ' FROM test_table WHERE column1 = $1 AND column2 = $2 AND column3 = $3';

    -- Add optional column4 filter
    IF IN_COLUMN4 IS NOT NULL THEN
        query := query || ' AND column4 = $4';
    END IF;

    query := query || ' LIMIT 1';

    -- Execute query and get result
    IF IN_COLUMN4 IS NOT NULL THEN
        EXECUTE query INTO RESULT USING IN_COLUMN1, IN_COLUMN2, IN_COLUMN3, IN_COLUMN4;
    ELSE
        EXECUTE query INTO RESULT USING IN_COLUMN1, IN_COLUMN2, IN_COLUMN3;
    END IF;

    RETURN RESULT;
END;
$$ LANGUAGE plpgsql
